// MiniBatchKMeans — faster for large datasets Skigen::MiniBatchKMeans<double> mbk(3, /*batch_size=*/30, /*max_iter=*/100, /*random_state=*/42); mbk.fit(X); std::cout << "=== MiniBatchKMeans (k=3, batch=30) ===
"; std::cout << "Inertia: " << mbk.inertia() << "
"; std::cout << "Centers:
" << mbk.cluster_centers() << "
